                  // 预览区域主题，默认空表示使用默认主题，可选值：default（默认主题）, dark（暗色主题）
                  previewTheme: "default",
                  // Markdown 源代码（编辑器初始化时显示的内容，可以是预填的 Markdown 文本）
                  markdown: "",
                  // 如果初始化时 textarea 值不为空，则追加 markdown 到 textarea（通常用于追加内容到现有文本）
                  appendMarkdown: "",
                  // 编辑器宽度（支持百分比如"100%"或像素值如"800px"）
                  width: "100%",
