                  delay: 300,
                  // 自动加载依赖模块文件（推荐保持 true，确保所有功能正常工作）
                  autoLoadModules: true,
                  // ===== 编辑器行为配置 =====
                  // 监听模式（是否实时预览，true 为开启监听，false 为手动预览）
