// ========================================
// 【密码修改】短信验证模式相关全局状态和函数
// ========================================

// 全局状态：当前验证模式 ('password' 或 'sms')
// PC端密码验证模式状态，默认为'password'（使用原密码验证）
let pcPasswordVerifyMode = "password";
// 移动端密码验证模式状态，默认为'password'（使用原密码验证）
let mobilePasswordVerifyMode = "password";

/**
 * 切换密码验证模式（密码验证 <-> 短信验证）
 * 该函数用于在修改密码时切换使用原密码验证还是短信验证码验证
 *
 * @param {string} platform - 平台标识，'pc' 或 'mobile'
 */
function toggleSmsVerifyMode(platform) {
  // 根据平台选择对应的DOM元素和状态变量
  if (platform === "pc") {
    // 获取PC端的密码输入区域
    const passwordSection = document.getElementById(
      "pc-password-verify-section",
    );
    // 获取PC端的短信验证区域
    const smsSection = document.getElementById("pc-sms-verify-section");
    // 获取切换按钮
    const toggleBtn = document.getElementById("pc-sms-toggle-btn");

    // 判断当前模式并切换
    if (pcPasswordVerifyMode === "password") {
      // 从密码验证模式切换到短信验证模式
      passwordSection.classList.add("hidden"); // 隐藏密码输入区域
      smsSection.classList.remove("hidden"); // 显示短信验证区域
      toggleBtn.textContent = "返回密码验证"; // 更新按钮文字
      pcPasswordVerifyMode = "sms"; // 更新状态为短信验证模式
      logMessage_Info("[密码修改] PC端切换到短信验证模式");
    } else {
      // 从短信验证模式切换回密码验证模式
      passwordSection.classList.remove("hidden"); // 显示密码输入区域
      smsSection.classList.add("hidden"); // 隐藏短信验证区域
      toggleBtn.textContent = "使用短信验证"; // 更新按钮文字
      pcPasswordVerifyMode = "password"; // 更新状态为密码验证模式
      // 清空短信验证码输入框
      const smsCodeInput = document.getElementById("pc-password-sms-code");
      if (smsCodeInput) smsCodeInput.value = "";
      logMessage_Info("[密码修改] PC端切换到密码验证模式");
    }
  } else if (platform === "mobile") {
    // 获取移动端的密码输入区域
    const passwordSection = document.getElementById(
      "mobile-password-verify-section",
    );
    // 获取移动端的短信验证区域
    const smsSection = document.getElementById("mobile-sms-verify-section");
    // 获取切换按钮
    const toggleBtn = document.getElementById("mobile-sms-toggle-btn");

    // 判断当前模式并切换
    if (mobilePasswordVerifyMode === "password") {
      // 从密码验证模式切换到短信验证模式
      passwordSection.classList.add("hidden"); // 隐藏密码输入区域
      smsSection.classList.remove("hidden"); // 显示短信验证区域
      toggleBtn.textContent = "返回密码验证"; // 更新按钮文字
      mobilePasswordVerifyMode = "sms"; // 更新状态为短信验证模式
      logMessage_Info("[密码修改] 移动端切换到短信验证模式");
    } else {
      // 从短信验证模式切换回密码验证模式
      passwordSection.classList.remove("hidden"); // 显示密码输入区域
      smsSection.classList.add("hidden"); // 隐藏短信验证区域
      toggleBtn.textContent = "使用短信验证"; // 更新按钮文字
      mobilePasswordVerifyMode = "password"; // 更新状态为密码验证模式
      // 清空短信验证码输入框
      const smsCodeInput = document.getElementById("mobile-password-sms-code");
      if (smsCodeInput) smsCodeInput.value = "";
      logMessage_Info("[密码修改] 移动端切换到密码验证模式");
    }
  }
}

/**
 * 发送密码重置短信验证码
 * 该函数用于在短信验证模式下发送验证码到用户绑定的手机号
 *
 * @param {string} platform - 平台标识，'pc' 或 'mobile'
 */
async function sendPasswordResetSmsCode(platform) {
  // 根据平台获取对应的发送按钮
  const btn = document.getElementById(
    platform === "pc" ? "pc-send-sms-btn" : "mobile-send-sms-btn",
  );

  try {
    // 首先获取当前用户的绑定手机号
    // 通过API获取用户资料信息
    const response = await callPythonAPI_raw("/api/user/profile", "GET");

    // 检查API响应是否成功
    if (!response.success) {
      // showModalAlert("获取用户信息失败，请稍后重试", "错误");
      Swal.fire({
        title: "错误",
        text: "获取用户信息失败，请稍后重试",
        icon: "error",
      });
      return;
    }

    // 检查用户是否已绑定手机号
    if (!response.phone) {
      // showModalAlert(
      //   '您尚未绑定手机号，无法使用短信验证。\n请先在"安全设置"中绑定手机号。',
      //   "提示"
      // );
      Swal.fire({
        title: "提示",
        text: '您尚未绑定手机号，无法使用短信验证。\n请先在"个人信息"中绑定手机号。',
        icon: "info",
      });
      return;
    }

    // 调用验证码模态框，发送短信验证码到绑定的手机号
    // openCaptchaModal 会弹出图形验证码窗口，验证通过后发送短信
    openCaptchaModal({
      phone: response.phone, // 用户绑定的手机号
      button: btn, // 触发按钮，用于显示倒计时
      originalText: "发送验证码", // 按钮原始文字，倒计时结束后恢复
      scene: "password_reset", // 场景标识，后端可据此做不同处理
    });

    logMessage_Info(
      `[密码修改] ${platform}端请求发送短信验证码到手机: ${response.phone}`,
    );
  } catch (e) {
    // 捕获网络错误或其他异常
    logMessage_Error("[密码修改] 获取手机号失败:", e);
    // showModalAlert("获取手机号失败: " + e.message, "错误");
    Swal.fire({
      title: "错误",
      text: "获取手机号失败: " + e.message,
      icon: "error",
    });
  }
}

/**
 * 重置密码修改面板的验证模式到默认状态
 * 当面板关闭或需要重置时调用
 *
 * @param {string} platform - 平台标识，'pc'、'mobile' 或 'all'
 */
function resetPasswordVerifyMode(platform) {
  // 重置PC端
  if (platform === "pc" || platform === "all") {
    pcPasswordVerifyMode = "password";
    const pcPasswordSection = document.getElementById(
      "pc-password-verify-section",
    );
    const pcSmsSection = document.getElementById("pc-sms-verify-section");
    const pcToggleBtn = document.getElementById("pc-sms-toggle-btn");
    const pcSmsCodeInput = document.getElementById("pc-password-sms-code");

    if (pcPasswordSection) pcPasswordSection.classList.remove("hidden");
    if (pcSmsSection) pcSmsSection.classList.add("hidden");
    if (pcToggleBtn) pcToggleBtn.textContent = "使用短信验证";
    if (pcSmsCodeInput) pcSmsCodeInput.value = "";
  }

  // 重置移动端
  if (platform === "mobile" || platform === "all") {
    mobilePasswordVerifyMode = "password";
    const mobilePasswordSection = document.getElementById(
      "mobile-password-verify-section",
    );
    const mobileSmsSection = document.getElementById(
      "mobile-sms-verify-section",
    );
    const mobileToggleBtn = document.getElementById("mobile-sms-toggle-btn");
    const mobileSmsCodeInput = document.getElementById(
      "mobile-password-sms-code",
    );

    if (mobilePasswordSection) mobilePasswordSection.classList.remove("hidden");
    if (mobileSmsSection) mobileSmsSection.classList.add("hidden");
    if (mobileToggleBtn) mobileToggleBtn.textContent = "使用短信验证";
    if (mobileSmsCodeInput) mobileSmsCodeInput.value = "";
  }
}

/**
 * PC端修改密码函数
 * 支持两种验证模式：原密码验证 或 短信验证码验证
 */
async function updatePassword() {
  // 弹出确认对话框，询问用户是否确认修改密码
  const confirmed = await jsShowConfirm(
    "确认修改密码",
    "您确定要修改您的登录密码吗？\n\n修改后需要使用新密码重新登录。",
  );
  // 如果用户取消操作，则直接返回
  if (!confirmed) {
    logMessage_Info("[修改密码] 用户取消了密码修改操作");
    return;
  }

  // 获取各个密码输入框的DOM元素
  const currentPassword = $("profile-current-password"); // 当前密码输入框
  const newPassword = $("profile-new-password"); // 新密码输入框
  const confirmPassword = $("profile-confirm-password"); // 确认新密码输入框

  // 检查必要的DOM元素是否存在
  if (!newPassword || !confirmPassword) return;

  // 判断当前是否使用短信验证模式
  const useSmsVerify = pcPasswordVerifyMode === "sms";
  // 如果是短信验证模式，获取短信验证码
  const smsCode = useSmsVerify
    ? document.getElementById("pc-password-sms-code")?.value?.trim()
    : null;

  // 根据验证模式进行不同的校验
  if (!useSmsVerify) {
    // 密码验证模式：检查原密码是否填写
    if (!currentPassword || !currentPassword.value) {
      // showModalAlert(
      //   '请填写当前密码，或点击"使用短信验证"通过短信验证码修改密码',
      //   "提示"
      // );
      Swal.fire({
        title: "提示",
        text: '请填写当前密码，或点击"使用短信验证"通过短信验证码修改密码',
        icon: "info",
      });
      return;
    }
  } else {
    // 短信验证模式：检查验证码是否填写
    if (!smsCode) {
      // showModalAlert("请填写短信验证码", "提示");
      Swal.fire({
        title: "提示",
        text: "请填写短信验证码",
        icon: "info",
      });
      return;
    }
    // 验证码格式校验（6位数字）
    if (!/^\d{6}$/.test(smsCode)) {
      // showModalAlert("短信验证码格式不正确，请输入6位数字", "提示");
      Swal.fire({
        title: "提示",
        text: "短信验证码格式不正确，请输入6位数字",
        icon: "info",
      });
      return;
    }
  }

  // 检查新密码是否填写
  if (!newPassword.value || !confirmPassword.value) {
    // showModalAlert("请填写新密码和确认新密码", "提示");
    Swal.fire({
      title: "提示",
      text: "请填写新密码和确认新密码",
      icon: "info",
    });
    return;
  }

  // 检查两次输入的新密码是否一致
  if (newPassword.value !== confirmPassword.value) {
    // showModalAlert("两次输入的密码不一致", "错误");
    Swal.fire({
      title: "错误",
      text: "两次输入的密码不一致",
      icon: "error",
    });
    return;
  }

  // 检查新密码强度
  // 在提交密码修改请求之前，先检查新密码是否为弱密码
  // 这可以防止用户设置不安全的密码，提高账户安全性
  var weakCheck = checkWeakPassword(newPassword.value);
  if (weakCheck.isWeak) {
    // 如果新密码过弱，显示具体的错误原因
    // showModalAlert(weakCheck.reason, "密码强度不足");
    Swal.fire({
      title: "错误",
      text: weakCheck.reason,
      icon: "error",
    });
    return;
  }

  // 检查新密码长度是否符合要求（最少6位）
  if (newPassword.value.length < 6) {
    // showModalAlert("密码长度至少为6个字符", "错误");
    Swal.fire({
      title: "错误",
      text: "密码长度至少为6个字符",
      icon: "error",
    });
    return;
  }

  // 检查当前用户信息是否可用
  if (!currentAuthUsername) {
    // showModalAlert("无法获取当前用户信息，请重新加载个人信息", "错误");
    Swal.fire({
      title: "错误",
      text: "无法获取当前用户信息，请重新加载个人信息",
      icon: "error",
    });
    return;
  }

  try {
    // 构建API请求体
    const requestBody = {
      username: currentAuthUsername, // 当前用户名
      new_password: newPassword.value, // 新密码
    };

    // 根据验证模式添加不同的验证字段
    if (useSmsVerify) {
      // 短信验证模式：传递短信验证码，原密码设为null
      requestBody.sms_code = smsCode;
      requestBody.old_password = null;
      logMessage_Info("[密码修改] PC端使用短信验证模式提交");
    } else {
      // 密码验证模式：传递原密码
      requestBody.old_password = currentPassword.value;
      logMessage_Info("[密码修改] PC端使用密码验证模式提交");
    }

    // 发送密码修改请求到后端API
    const response = await fetch("/auth/admin/reset_password", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Session-ID": sessionUUID,
      },
      body: JSON.stringify(requestBody),
    });

    // 解析API响应
    const result = await response.json();

    if (result.success) {
      // 密码修改成功
      // showModalAlert("密码修改成功！", "成功");
      Swal.fire({
        title: "成功",
        text: "密码修改成功！",
        icon: "success",
      });
      // 清空所有输入框
      if (currentPassword) currentPassword.value = "";
      newPassword.value = "";
      confirmPassword.value = "";
      // 重置验证模式到默认状态（密码验证）
      resetPasswordVerifyMode("pc");
    } else {
      // 密码修改失败，显示错误信息
      const errorMsg = useSmsVerify
        ? result.message || "请检查短信验证码是否正确"
        : result.message || "请检查当前密码是否正确";
      // showModalAlert(`修改失败: ${errorMsg}`, "错误");
      Swal.fire({
        title: "错误",
        text: `修改失败: ${errorMsg}`,
        icon: "error",
      });
    }
  } catch (e) {
    // 捕获网络错误或其他异常
    logMessage_Error("修改密码失败:", e);
    // showModalAlert(`修改失败: ${e.message}`, "错误");
    Swal.fire({
      title: "错误",
      text: `修改失败: ${e.message}`,
      icon: "error",
    });
  }
}

async function generate2FA() {
  try {
    const response = await fetch("/auth/2fa/generate", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Session-ID": sessionUUID,
      },
    });
    const result = await response.json();

    if (!result.success) {
      // showModalAlert(`生成2FA失败: ${result.message}`, "错误");
      Swal.fire({
        title: "错误",
        text: `生成2FA失败: ${result.message}`,
        icon: "error",
      });
      return;
    }
    const setupDiv = $("profile-2fa-setup");
    const actionsDiv = $("profile-2fa-actions");
    if (setupDiv) setupDiv.classList.remove("hidden");
    if (actionsDiv) actionsDiv.classList.add("hidden");
    const secretSpan = $("profile-2fa-secret");
    if (secretSpan && result.secret) {
      secretSpan.textContent = result.secret;
    }
    const qrCanvas = $("profile-2fa-qr");
    if (qrCanvas && result.qr_uri) {
      if (typeof QRCode !== "undefined") {
        qrCanvas.width = 200;
        qrCanvas.height = 200;

        QRCode.toCanvas(
          qrCanvas,
          result.qr_uri,
          { width: 200 },
          function (error) {
            if (error) {
              logMessage_Error("QR Code generation error:", error);
              // showModalAlert("二维码生成失败", "错误");
              Swal.fire({
                title: "错误",
                text: "二维码生成失败",
                icon: "error",
              });
            } else {
              logMessage_Info("QR Code generated successfully");
            }
          },
        );
      } else {
        logMessage_Error("QRCode库未加载");
        // showModalAlert("QRCode库未加载，请刷新页面重试", "错误");
        Swal.fire({
          title: "错误",
          text: "QRCode库未加载，请刷新页面重试",
          icon: "error",
        });
      }
    }
  } catch (e) {
    logMessage_Error("生成2FA失败:", e);
    // showModalAlert(`生成失败: ${e.message}`, "错误");
    Swal.fire({
      title: "错误",
      text: `生成失败: ${e.message}`,
      icon: "error",
    });
  }
}

