async function mobileStartAllAccounts() {
  try {
    // ========== 步骤1：获取账号总数 ==========
    // 从页面元素中读取账号计数
    const count = parseInt($("multi-account-count")?.textContent || "0", 10);

    // ========== 步骤2：验证账号列表是否为空 ==========
    if (!count || count <= 0) {
      showModalAlert("账号列表为空，无法启动", "错误");
      return;
    }

    // ========== 步骤3：获取已添加的账号列表 ==========
    // 调用loadInitialData()获取当前所有已添加的账号数据
    // 使用try-catch确保即使获取失败也能继续执行（容错处理）
    let addedUsernames = _getMultiAccountListUsernames();
    try {
      if (addedUsernames.length === 0) {
        const initialData = await loadInitialData();
        if (
          initialData &&
          initialData.accounts &&
          Array.isArray(initialData.accounts)
        ) {
          // 从accounts数组中提取所有账号的username字段
          // 这些是当前已添加到多账号管理的所有账号
          addedUsernames = initialData.accounts
            .map((acc) => acc.username)
            .filter(Boolean); // 过滤掉空值
        }
      }
    } catch (error) {
      // 如果获取账号列表失败，记录错误但不阻止继续执行
      console.error("[mobileStartAllAccounts] 获取账号列表失败:", error);
    }

    // ========== 步骤4：欠费检查（只检查已添加的账号）==========
    // 【重要】只检查已添加账号的欠费情况，若获取账号列表失败则跳过检查
    const canStart =
      addedUsernames.length > 0
        ? await checkOverdueBeforeStart(addedUsernames)
        : true;
    if (!canStart) {
      // 欠费检查未通过，用户选择不缴费或取消，直接返回不启动任务
      return;
    }
    // ========== 欠费检查结束 ==========

    // ========== 步骤5：读取启动配置 ==========
    const randomDelayCheck = document.getElementById(
      "mobile-multi-random-delay-check",
    );
    const onlyIncompleteCheck = document.getElementById(
      "mobile-multi-only-incomplete-check",
    );
    const use_delay = randomDelayCheck ? randomDelayCheck.checked : true;
    const min_delay = 0;
    const max_delay = 300;
    const run_only_incomplete = onlyIncompleteCheck
      ? onlyIncompleteCheck.checked
      : true;

    // ========== 步骤6：调用后端API启动所有账号 ==========
    showModalAlert(`正在启动全部 ${count} 个账号...`, "提示");
    const result = await callPythonAPI(
      "multi_start_all_accounts",
      min_delay,
      max_delay,
      use_delay,
      run_only_incomplete,
    );

    // ========== 步骤7：处理返回结果 ==========
    if (!result || !result.success) {
      showModalAlert(result?.message || "启动全部账号失败", "错误");
      return;
    }

    showModalAlert("已发送全部启动指令", "成功");
  } catch (error) {
    console.error("[移动端] 启动全部账号失败:", error);
    showModalAlert("启动全部账号失败", "错误");
  }
}
