    html += createInput(
      "IP_Location",
      "uapipro_api_key",
      "UapiPro API Key",
      "text",
      "用于调用 https://uapis.cn/api/v1/network/ipinfo（Bearer Token）",
    );
    // html +=
    //   '<h5 class="font-bold text-base text-sky-800 border-b pb-1 mt-4 mb-2">第三方 API 配置</h5>';
    // ==================== 网站备案信息配置 ====================
    // 添加网站备案（Beian）相关配置项，包括ICP备案号和公安网备案号
