// =============================================================================
// 密码恢复任务管理功能
// =============================================================================

/**
 * 更新密码恢复任务列表显示
 *
 * 功能说明：
 *   此函数负责将后端返回的密码恢复任务状态数据渲染到前端界面上。
 *   它会同时更新桌面版和移动版两个不同的任务列表容器，确保在不同设备上
 *   用户都能看到最新的任务状态。
 *
 * 参数：
 *   tasks (Array) - 任务状态数组，每个任务对象包含以下字段：
 *     - account (String): 正在尝试恢复密码的账号名称
 *     - status (String): 任务当前状态，可能的值包括：
 *         * "running" - 任务正在运行中
 *         * "success" - 密码已成功找到
 *         * "failed" - 任务失败（密码未找到或出现错误）
 *         * "stopped" - 任务已被用户手动停止
 *     - attempts (Number): 已经尝试的密码组合数量
 *     - password (String, 可选): 如果status为"success"，此字段包含找到的密码
 *     - start_time (String, 可选): 任务开始的时间戳（格式化后的字符串）
 *     - end_time (String, 可选): 任务结束的时间戳（格式化后的字符串）
 *
 * 返回值：
 *   无返回值（void）
 *
 * 实现细节：
 *   1. 获取DOM元素：分别获取桌面版和移动版的任务列表容器
 *   2. 空状态处理：如果没有任务，显示友好的提示信息
 *   3. 任务卡片生成：遍历每个任务，根据状态生成不同样式的卡片HTML
 *   4. 状态着色：使用Tailwind CSS的颜色类，为不同状态应用不同的视觉效果
 *   5. DOM更新：将生成的HTML插入到对应的容器中
 */
function updateBruteforceTaskList(tasks) {
  // 通过ID选择器获取桌面版任务列表的DOM容器
  // 这个容器通常在主界面的管理面板中
  const desktopList = document.getElementById("bruteforce-task-list");

  // 通过ID选择器获取移动版任务列表的DOM容器
  // 移动版界面通常有独立的、更紧凑的布局
  const mobileList = document.getElementById("mobile-bruteforce-task-list");

  // 边界情况处理：检查tasks是否为空、未定义或空数组
  // 这是一个重要的防御性编程实践，避免在空数据时出现错误
  if (!tasks || tasks.length === 0) {
    // 定义空状态的提示消息HTML
    // 使用Tailwind CSS类来实现居中、灰色、适当的内边距
    const emptyMessage =
      '<div class="text-slate-400 text-center py-8 text-sm">暂无任务</div>';

    // 如果桌面版容器存在，则插入空状态消息
    if (desktopList) desktopList.innerHTML = emptyMessage;

    // 如果移动版容器存在，则插入更紧凑的空状态消息
    // 注意移动版使用更小的字体(text-xs)和内边距(py-4)
    if (mobileList)
      mobileList.innerHTML =
        '<div class="text-slate-400 text-center py-4 text-xs">暂无任务</div>';

    // 处理完空状态后，直接返回，不再执行后续的任务渲染逻辑
    return;
  }

  // 初始化两个字符串变量，用于累积生成的HTML代码
  // 分别对应桌面版和移动版的任务列表HTML
  let desktopHTML = "";
  let mobileHTML = "";

  // 遍历tasks数组中的每一个任务对象
  // 使用forEach方法可以简洁地处理数组中的每个元素
  tasks.forEach((task) => {
    // ====================================================================
    // 步骤1：根据任务状态确定视觉样式
    // ====================================================================

    // 初始化状态相关的变量，默认值对应"运行中"状态
    let statusColor = "slate"; // Tailwind颜色类名，slate表示灰色系
    let statusIcon = "⏳"; // Unicode图标，沙漏表示进行中
    let statusText = "运行中"; // 中文状态文本

    // 通过if-else链检查任务的status字段，设置相应的视觉元素
    if (task.status === "success") {
      // 成功状态：使用绿色主题
      statusColor = "green"; // 绿色传达积极、完成的信息
      statusIcon = "✅"; // 对勾图标，直观表示成功
      statusText = "成功"; // 简洁的状态文本
    } else if (task.status === "failed") {
      // 失败状态：使用红色主题
      statusColor = "red"; // 红色警示失败或错误
      statusIcon = "❌"; // 叉号图标，表示未通过
      statusText = "失败"; // 明确的失败提示
    } else if (task.status === "stopped") {
      // 已停止状态：使用橙色主题
      statusColor = "orange"; // 橙色表示警告或中性状态
      statusIcon = "⏸️"; // 暂停图标，表示中断
      statusText = "已停止"; // 说明是用户主动停止
    }
    // 注意：如果status为"running"或其他未知值，将保持默认的slate样式

    // ====================================================================
    // 步骤2：生成桌面版任务卡片HTML
    // ====================================================================

    // 使用模板字符串构建HTML，可以方便地嵌入变量和表达式
    desktopHTML += `
            <div class="p-3 border border-${statusColor}-200 bg-${statusColor}-50 rounded-lg">
                <!-- 任务卡片的外层容器，使用状态颜色的浅色背景和边框 -->
                <!-- p-3: 内边距，border: 边框，rounded-lg: 圆角 -->
                
                <div class="flex justify-between items-start mb-2">
                    <!-- 顶部信息行：使用flex布局，左右分布，顶部对齐 -->
                    
                    <div>
                        <!-- 左侧：账号名称和状态标签 -->
                        
                        <span class="font-semibold text-slate-800">${
                          task.account
                        }</span>
                        <!-- 显示账号名称，使用加粗字体和深灰色 -->
                        
                        <span class="ml-2 text-sm px-2 py-0.5 rounded bg-${statusColor}-100 text-${statusColor}-700">
                            <!-- 状态徽章：使用状态颜色的浅色背景和深色文字 -->
                            <!-- ml-2: 左边距与账号名分隔，px-2 py-0.5: 内边距，rounded: 圆角 -->
                            ${statusIcon} ${statusText}
                            <!-- 显示状态图标和文字 -->
                        </span>
                    </div>
                    
                    ${
                      task.status === "running"
                        ? `
                        <!-- 右侧：仅在任务运行中时显示停止按钮 -->
                        <!-- 使用三元表达式进行条件渲染 -->
                        
                        <button onclick="stopBruteforce('${task.account}')" class="text-xs btn btn-ghost !py-1 !px-2">
                            <!-- 停止按钮：调用stopBruteforce函数，传入账号名称 -->
                            <!-- btn-ghost: 幽灵按钮样式（透明背景） -->
                            <!-- !py-1 !px-2: 使用!important覆盖默认按钮尺寸 -->
                            停止
                        </button>
                    `
                        : ""
                    }
                    <!-- 如果不是运行中状态，则不渲染按钮（空字符串） -->
                </div>
                
                <div class="text-sm text-slate-600">
                    <!-- 详细信息区域：较小的字体和中等灰色 -->
                    
                    <div>已尝试: ${task.attempts || 0} 个密码</div>
                    <!-- 显示尝试次数，使用 || 运算符提供默认值0 -->
                    <!-- 如果task.attempts为undefined/null/0，则显示0 -->
                    
                    ${
                      task.password
                        ? `<div class="text-green-600 font-semibold">密码: ${task.password}</div>`
                        : ""
                    }
                    <!-- 条件渲染：仅当找到密码时才显示此行 -->
                    <!-- 使用绿色和加粗突出显示找到的密码 -->
                    
                    ${
                      task.start_time
                        ? `<div class="text-xs text-slate-500 mt-1">开始时间: ${task.start_time}</div>`
                        : ""
                    }
                    <!-- 条件渲染：如果有开始时间，则显示 -->
                    <!-- text-xs: 更小的字号，text-slate-500: 更浅的灰色，mt-1: 顶部边距 -->
                </div>
            </div>
        `;

    // ====================================================================
    // 步骤3：生成移动版任务卡片HTML（更紧凑的版本）
    // ====================================================================

    // 移动版的设计理念：在小屏幕上节省空间，简化信息展示
    mobileHTML += `
            <div class="p-2 border border-${statusColor}-200 bg-${statusColor}-50 rounded text-xs">
                <!-- 外层容器：比桌面版更小的内边距(p-2)和字体(text-xs) -->
                
                <div class="flex justify-between items-center mb-1">
                    <!-- 顶部信息行：居中对齐，较小的底部边距 -->
                    
                    <span class="font-semibold">${task.account}</span>
                    <!-- 账号名称：加粗但不设置颜色，继承父元素的text-xs -->
                    
                    <span class="text-xs px-1.5 py-0.5 rounded bg-${statusColor}-100 text-${statusColor}-700">
                        <!-- 状态徽章：更小的内边距以节省空间 -->
                        ${statusIcon} ${statusText}
                    </span>
                </div>
                
                <div class="text-xs text-slate-600">
                    <!-- 详细信息区域：极小字体 -->
                    
                    尝试: ${task.attempts || 0} 个
                    <!-- 简化的尝试次数显示，省略"已"和"密码"等冗余词汇 -->
                    
                    ${
                      task.password
                        ? `<div class="text-green-600 font-semibold">密码: ${task.password}</div>`
                        : ""
                    }
                    <!-- 密码显示逻辑与桌面版相同 -->
                    <!-- 注意：移动版省略了开始时间，进一步简化界面 -->
                </div>
            </div>
        `;
  });
  // forEach循环结束，此时desktopHTML和mobileHTML已包含所有任务卡片的HTML代码

  // ====================================================================
  // 步骤4：更新DOM，将生成的HTML插入到页面中
  // ====================================================================

  // 如果桌面版容器存在于DOM中，则更新其innerHTML
  // innerHTML会完全替换容器内的现有内容
  if (desktopList) desktopList.innerHTML = desktopHTML;

  // 如果移动版容器存在于DOM中，则更新其innerHTML
  if (mobileList) mobileList.innerHTML = mobileHTML;

  // 函数执行完毕，任务列表已更新到页面上
  // 用户现在可以看到所有任务的最新状态
}

/**
 * 加载应用初始数据的统一封装函数
 *
 * 功能概述：
 *   这是一个关键的初始化函数，负责在应用启动或用户登录后从后端获取
 *   必要的初始数据。它不仅调用API，还会根据返回的数据自动执行相应的
 *   UI更新操作，特别是为超级管理员自动更新密码恢复任务列表。
 *
 * 核心功能：
 *   1. 统一调用：将所有对 get_initial_data API 的调用集中到此函数
 *   2. 数据获取：从后端获取用户列表、最后登录用户、权限信息等初始数据
 *   3. 自动更新：如果响应中包含密码恢复任务列表（仅超级管理员可见），
 *      自动调用 updateBruteforceTaskList() 更新UI
 *   4. 错误处理：捕获并记录API调用过程中的任何错误
 *
 * 设计优势：
 *   - 代码复用：避免在多处重复写API调用和任务列表更新逻辑
 *   - 维护性：将来如果需要修改初始化逻辑，只需修改此函数
 *   - 一致性：确保所有初始化流程都执行相同的更新逻辑
 *   - 可测试性：将逻辑封装后更容易进行单元测试
 *
 * 调用时机：
 *   - 应用首次加载时
 *   - 用户登录成功后
 *   - 用户切换账号后
 *   - 需要刷新用户数据时
 *
 * 返回值：
 *   Promise<Object> - 一个Promise对象，resolve时返回包含初始数据的对象
 *   返回的对象结构（示例）：
 *   {
 *     success: true,                    // API调用是否成功
 *     users: [...],                     // 用户列表数组
 *     last_login_user: "username",      // 最后登录的用户名
 *     is_superadmin: true/false,        // 当前用户是否为超级管理员
 *     bruteforce_task_list: [...],      // (可选)密码恢复任务列表，仅超级管理员有此字段
 *     // ... 其他初始数据字段
 *   }
 *
 * 异常处理：
 *   如果API调用失败，函数会：
 *   1. 在控制台输出错误日志（包含 [初始化] 前缀便于过滤）
 *   2. 将错误向上抛出（throw），让调用者可以捕获并处理
 *
 * 使用示例：
 *   try {
 *     const data = await loadInitialData();
 *     if (data.success) {
 *       console.log('初始化成功', data);
 *     }
 *   } catch (error) {
 *     console.error('初始化失败', error);
 *   }
 */
// ============================================================================
// 全局变量：用于loadInitialData的限流机制
// ============================================================================
let lastInitialDataRequest = 0; // 上次请求的时间戳（毫秒）
let lastInitialDataResponse = null; // 缓存的上次响应数据
const INITIAL_DATA_RATE_LIMIT = 500; // 限流时间：500毫秒（0.5秒）

/**
 * 加载应用初始数据的统一函数（带限流机制）
 *
 * 功能：
 * 1. 调用后端 get_initial_data API
 * 2. 处理返回的用户列表、最后登录用户等信息
 * 3. 如果是超级管理员，自动更新密码恢复任务列表
 * 4. 如果在多账号模式，自动获取并更新所有账号状态
 * 5. 支持发送前端日志到后端
 * 6. 实现限流：0.5秒内只允许一次请求，重复请求返回缓存数据
 *
 * 参数：
 *   options (Object, 可选) - 配置选项：
 *     - frontend_logs (Array|Object): 要发送到后端的前端日志
 *     - force (Boolean): 是否强制请求（忽略限流，默认false）
 *
 * 返回值：
 *   Promise<Object> - 包含初始数据的对象
 */
async function loadInitialData(options = {}) {
  // 使用try-catch块进行错误处理，这是异步函数的最佳实践
  try {
    // ====================================================================
    // 步骤1：限流检查
    // ====================================================================

    // 获取当前时间戳（毫秒）
    const now = Date.now();

    // 计算距离上次请求的时间间隔
    const timeSinceLastRequest = now - lastInitialDataRequest;

    // 检查是否需要应用限流
    // 如果不是强制请求，且距离上次请求时间小于限流时间，且有缓存数据
    if (
      !options.force &&
      timeSinceLastRequest < INITIAL_DATA_RATE_LIMIT &&
      lastInitialDataResponse
    ) {
      // 记录日志：请求被限流
      console.log(
        `[初始化] 请求被限流，返回缓存数据（距上次请求 ${timeSinceLastRequest}ms）`,
      );

      // 直接返回缓存的响应数据
      // 这样可以减少对后端的压力，提高响应速度
      return lastInitialDataResponse;
    }

    // ====================================================================
    // 步骤2：准备API调用参数
    // ====================================================================

    // 构建传递给后端的参数对象
    const params = {};

    // 如果提供了前端日志，添加到参数中
    if (options.frontend_logs) {
      params.frontend_logs = options.frontend_logs;
      console.log(
        "[初始化] 携带前端日志数据，数量:",
        Array.isArray(options.frontend_logs) ? options.frontend_logs.length : 1,
      );
    }

    // ====================================================================
    // 步骤3：调用后端API获取初始数据
    // ====================================================================

    // 更新最后请求时间戳
    lastInitialDataRequest = now;

    // 使用await关键字等待callPythonAPI的Promise完成
    // callPythonAPI是应用中已存在的函数，负责与Python后端通信
    // "get_initial_data"是API端点的标识符，后端会据此返回相应数据
    const response = await callPythonAPI("get_initial_data", params);

    // 此时response已包含后端返回的完整数据对象
    // 如果API调用失败，callPythonAPI可能会抛出异常，会被catch块捕获

    // ====================================================================
    // 步骤4：缓存响应数据
    // ====================================================================

    // 将响应数据缓存起来，供下次限流时使用
    lastInitialDataResponse = response;

    // ====================================================================
    // 步骤5：检查响应的有效性和成功状态
    // ====================================================================

    // 双重检查：确保response不为null/undefined，且success字段为true
    // 这是一个防御性检查，防止后端返回意外的数据结构
    if (response && response.success) {
      // response对象存在且表示操作成功

      // ================================================================
      // 步骤6：处理密码恢复任务列表（仅超级管理员）
      // ================================================================

      // 条件判断：检查response中是否存在bruteforce_task_list字段
      // 这个字段只有在以下情况下才会存在：
      //   1. 当前登录用户是超级管理员
      //   2. 后端配置了密码恢复功能
      //   3. 存在正在进行或已完成的密码恢复任务
      if (response.bruteforce_task_list) {
        // 如果存在任务列表数据，说明当前用户有权限查看

        // 调用 updateBruteforceTaskList 函数更新UI
        // 将后端返回的任务数组传递给该函数进行渲染
        // 这个调用是自动的、透明的，调用loadInitialData的代码
        // 无需关心任务列表的更新，实现了关注点分离
        updateBruteforceTaskList(response.bruteforce_task_list);

        // 日志记录：帮助开发者调试，了解任务列表更新的触发情况
        console.log(
          "[初始化] 已自动更新密码恢复任务列表，任务数量:",
          response.bruteforce_task_list.length,
        );
      }
      // 如果bruteforce_task_list不存在，说明：
      //   - 当前用户不是超级管理员，或
      //   - 没有任何密码恢复任务
      // 这种情况下不执行任何操作，保持界面原样

      // ================================================================
      // 步骤7：处理多账号模式的账号状态（如果在多账号模式）
      // ================================================================

      // 检查是否返回了accounts字段（多账号状态信息）
      if (response.accounts && Array.isArray(response.accounts)) {
        // 如果存在accounts数据，说明当前用户在多账号模式

        // 日志记录：记录获取到的账号数量
        console.log(
          "[初始化] 已自动获取多账号状态，账号数量:",
          response.accounts.length,
        );

        // 注意：accounts数据已经在response中
        // 调用方可以直接从response.accounts中提取并使用
        // 这里不需要额外处理，因为调用方会处理这些数据
      }

      if (response.auth_group) {
        logMessage_Info("[初始化] 获取到用户权限组:", response.auth_group);
        if (
          currentUserData.auth_group !== response.auth_group ||
          currentUserData.group !== response.auth_group
        ) {
          currentUserData.auth_group = response.auth_group;
          currentUserData.group = response.auth_group;
          console.log("[初始化] 用户权限组已更新为:", response.auth_group);
        }
      }
    }

    // ====================================================================
    // 步骤8：返回完整的响应对象
    // ====================================================================

    logMessage_Info("[初始化] 初始数据加载完成:", response);

    // 将response返回给调用者
    // 调用者可以从中提取需要的数据（如用户列表、权限信息等）
    // 注意：即使response.success为false，我们仍然返回它
    // 让调用者自行决定如何处理失败情况（更灵活的设计）
    return response;
  } catch (error) {
    // ====================================================================
    // 错误处理块：捕获任何在try块中发生的异常
    // ====================================================================

    // 可能的错误来源：
    //   1. callPythonAPI内部的网络错误（如超时、连接失败）
    //   2. 后端返回的非预期响应格式导致的解析错误
    //   3. updateBruteforceTaskList中的DOM操作错误（较少见）

    // 使用console.error输出错误到浏览器控制台
    // '[初始化]' 前缀便于在控制台中过滤和定位相关日志
    // error对象包含完整的错误堆栈信息，有助于调试
    console.error("[初始化] 加载初始数据失败:", error);

    // 重新抛出错误（re-throw）
    // 这样做的目的是让调用者也能感知到错误的发生
    // 调用者可以决定如何响应错误：
    //   - 显示错误提示给用户
    //   - 重试加载
    //   - 回退到默认状态
    //   - 记录错误日志到服务器
    throw error;

    // 注意：如果不re-throw，调用者会认为函数成功执行（返回undefined）
    // 这会导致错误被静默吞噬，难以发现和调试问题
  }

  // 函数结束
  // 正常情况下，执行流程会在return response处结束
  // 错误情况下，会在throw error处结束
}

// ============================================================================
// 彩虹易支付系统 - 前端JavaScript实现
// ============================================================================
// 本模块实现了彩虹易支付系统的所有前端交互功能
// 包括：创建订单、查询状态、订单列表管理、支付配置、日志查看等
// 所有函数都有详细的中文注释，便于理解和维护
// ============================================================================

// ========================================
// 全局变量定义区域
// ========================================

// 订单轮询定时器：用于定时查询订单支付状态
// 当用户创建订单后，会启动定时器每3秒查询一次订单状态
// 支付成功或超时后会自动清除定时器
let paymentPollingTimer = null;

// 订单轮询计数器：记录已经轮询的次数
// 最多轮询20次（约1分钟），避免无限轮询浪费资源
let paymentPollingCount = 0;

// 订单列表当前页码：用于分页显示订单列表
// 默认从第1页开始，点击"下一页"/"上一页"会更新此值
let currentOrdersPage = 1;

// 订单列表每页显示数量：控制每页显示多少条订单
// 设置为10条，既不会太多导致加载慢，也不会太少需要频繁翻页
let ordersPerPage = 10;

// 当前筛选的订单状态：用于过滤订单列表
// 可选值：'all'（全部）、'pending'（待支付）、'paid'（已支付）、'closed'（已关闭）
let currentOrderStatus = "all";

// ========================================
// 打开支付弹窗函数
// ========================================
/**
 * 打开支付弹窗，让用户输入支付金额和选择支付方式
 *
 * 功能说明：
 * 1. 显示支付弹窗（payment-modal）
 * 2. 从后端加载启用的支付方式并动态显示
 * 3. 重置表单到初始状态
 *
 * 调用时机：
 * - 用户点击个人中心的"在线支付"按钮时
 * - 用户点击订单列表中的"继续支付"按钮时
 *
 * @returns {void} 无返回值
 */
async function openPaymentModal() {
  // 步骤1：获取支付弹窗DOM元素
  const modal = document.getElementById("payment-modal");

  // 步骤2：检查弹窗元素是否存在
  // 如果不存在，说明HTML结构有问题，输出错误并返回
  if (!modal) {
    console.error("[支付] 支付弹窗元素不存在");
    return;
  }

  // 步骤3：显示支付弹窗
  // 移除'hidden'类名（如果存在），并添加'flex'类名使弹窗居中显示
  modal.classList.remove("hidden");
  modal.style.display = "flex";

  // 步骤4：重置表单到初始状态
  // 清空金额输入框，避免显示上次输入的金额
  document.getElementById("payment-amount").value = "";
  // 恢复商品描述为默认值"在线支付"
  document.getElementById("payment-product-name").value = "在线支付";

  // 步骤5：从后端加载启用的支付方式
  // 管理员可能随时修改支付配置，所以每次打开弹窗都需要重新加载
  try {
    // 调用后端API获取支付配置
    // 使用await等待异步请求完成，确保数据加载后再继续
    const response = await fetch("/api/admin/payment/config", {
      method: "GET",
      headers: {
        "Content-Type": "application/json",
        "X-Session-ID": sessionUUID,
      },
    });

    // 将响应转换为JSON格式
    const result = await response.json();

    // 步骤6：检查API调用是否成功
    if (result.success && result.enabled_payment_methods) {
      // 获取启用的支付方式列表
      // 例如：["alipay", "wxpay"]
      const enabledMethods = result.enabled_payment_methods;

      // 获取支付方式容器DOM元素
      const container = document.getElementById("payment-methods-container");

      // 步骤7：动态生成支付方式选项
      // 清空容器，准备重新生成
      container.innerHTML = "";

      // 检查是否有启用的支付方式
      // 如果后端没有返回任何启用的支付方式，显示提示信息
      if (enabledMethods.length === 0) {
        // 创建提示HTML并插入容器
        container.innerHTML = `
                    <div class="text-center py-6 text-slate-500">
                        <p class="text-sm">暂无可用的支付方式</p>
                        <p class="text-xs mt-1">请联系管理员启用支付方式</p>
                    </div>
                `;
        return; // 直接返回，不再继续执行
      }

      // 遍历启用的支付方式，为每个方式创建一个单选按钮
      enabledMethods.forEach((method, index) => {
        // 从全局配置对象(PAYMENT_METHODS)中获取当前支付方式的配置
        // 如果配置不存在（未知的支付方式），使用默认配置
        const config = PAYMENT_METHODS[method] || {
          name: method.toUpperCase(), // 使用代码本身作为显示名称，转为大写
          icon: "emoji", // 默认使用emoji图标类型
          svg: "💳", // 使用通用的信用卡emoji作为备用
          borderColor: "hover:border-slate-500", // 使用中性的灰色边框
          textColor: "text-slate-600", // 使用中性的灰色文字
          description: "在线支付",
        };

        // 根据图标类型生成图标HTML
        // 如果icon字段为'svg'，使用svg字段的SVG代码
        // 否则使用icon字段作为emoji图标
        const iconHtml =
          config.icon === "svg"
            ? config.svg // 直接使用SVG代码（已包含样式类）
            : `<span class="text-lg">${config.icon}</span>`; // emoji图标，包裹在span中

        // 创建支付方式选项的HTML字符串
        // 使用模板字符串拼接，支持变量插值
        // 注意：第一个选项(index === 0)会被自动选中(checked属性)
        const optionHTML = `
                    <label class="flex items-center p-3 border-2 border-slate-200 rounded-lg cursor-pointer ${
                      config.borderColor
                    } transition-colors">
                        <!-- 单选按钮：name属性保证同组单选，value属性用于提交数据 -->
                        <input type="radio" name="payment-method" value="${method}" 
                            class="w-4 h-4 ${config.textColor}" ${
                              index === 0 ? "checked" : ""
                            } />
                        <!-- 支付方式图标：SVG或emoji，根据配置动态生成 -->
                        <span class="ml-3 flex items-center gap-2">
                            ${iconHtml}
                            <!-- 支付方式名称：显示给用户的中文名称 -->
                            <span class="text-sm font-medium text-slate-700">${
                              config.name
                            }</span>
                        </span>
                    </label>
                `;

        // 将HTML字符串插入到容器的末尾
        // insertAdjacentHTML比innerHTML更高效，不会重新解析整个容器
        container.insertAdjacentHTML("beforeend", optionHTML);
      });

      // 输出日志：记录成功加载的支付方式
      console.log("[支付] 已加载启用的支付方式:", enabledMethods);
    } else {
      // API调用失败或没有启用的支付方式
      // 使用Swal.fire显示友好的错误提示
      Swal.fire({
        icon: "warning",
        title: "提示",
        text: "暂无可用的支付方式，请联系管理员",
        confirmButtonText: "确定",
      });

      // 输出警告日志
      console.warn("[支付] 获取支付方式失败:", result.message);
    }
  } catch (error) {
    // 捕获网络错误或其他异常
    console.error("[支付] 加载支付方式时出错:", error);

    // 显示错误提示
    Swal.fire({
      icon: "error",
      title: "错误",
      text: "加载支付方式失败，请稍后重试",
      confirmButtonText: "确定",
    });
  }
}

// ========================================
// 关闭支付弹窗函数
// ========================================
/**
 * 关闭支付弹窗
 *
 * 功能说明：
 * 1. 隐藏支付弹窗
 * 2. 清理表单数据
 *
 * 调用时机：
 * - 用户点击"取消"按钮时
 * - 用户点击弹窗外部区域时
 * - 用户点击关闭按钮（X）时
 *
 * @returns {void} 无返回值
 */
function closePaymentModal() {
  // 获取支付弹窗DOM元素
  const modal = document.getElementById("payment-modal");

  // 检查元素是否存在
  if (!modal) return;

  // 隐藏弹窗：添加'hidden'类名
  modal.classList.add("hidden");
  modal.style.display = "none";

  // 输出日志
  console.log("[支付] 支付弹窗已关闭");
}

// ========================================
// 创建支付订单函数
// ========================================
/**
 * 创建支付订单并跳转到支付页面
 *
 * 功能说明：
 * 1. 验证用户输入（金额、支付方式、商品名称）
 * 2. 获取当前页面的app_host并验证其有效性
 * 3. 调用后端API创建支付订单
 * 4. 在新窗口打开支付URL
 * 5. 启动订单状态轮询，实时查询支付结果
 *
 * 参数验证规则：
 * - amount: 必须大于0.01元
 * - pay_type: 必须选择一个支付方式
 * - product_name: 不能为空
 *
 * @returns {Promise<void>} 无返回值的Promise
 */
async function createPaymentOrder() {
  // 步骤1：获取用户输入的支付金额
  // 使用trim()去除首尾空格，避免用户误输入空格
  const amount = document.getElementById("payment-amount").value.trim();

  // 步骤2：获取选中的支付方式
  // querySelector获取被选中的单选按钮的value属性
  const payType = document.querySelector(
    'input[name="payment-method"]:checked',
  )?.value;

  // 步骤3：获取商品名称
  const productName = document
    .getElementById("payment-product-name")
    .value.trim();

  // 步骤4：参数验证 - 检查金额是否为空
  if (!amount) {
    // 使用showModalAlert显示友好的错误提示
    // showModalAlert是移动端兼容的弹窗函数，避免使用Swal.fire
    showModalAlert("请输入支付金额", "提示");
    return; // 验证失败，终止函数执行
  }

  // 步骤5：参数验证 - 检查金额是否小于最低限额
  // parseFloat将字符串转换为浮点数，便于数值比较
  if (parseFloat(amount) < 0.01) {
    // 使用showModalAlert显示最低金额限制的提示
    showModalAlert("支付金额不能低于0.01元", "提示");
    return;
  }

  // 步骤6：参数验证 - 检查是否选择了支付方式
  if (!payType) {
    // 使用showModalAlert提示用户选择支付方式
    showModalAlert("请选择支付方式", "提示");
    return;
  }

  // 步骤7：参数验证 - 检查商品名称是否为空
  if (!productName) {
    // 使用showModalAlert提示用户输入商品描述
    showModalAlert("请输入商品描述", "提示");
    return;
  }

  // 步骤8：获取当前页面的app_host（完整URL，包含协议和域名）
  // location.protocol 返回协议（如：https:）
  // location.host 返回域名和端口（如：example.com:8080）
  const appHost = window.location.protocol + "//" + window.location.host;

  // 输出日志：记录即将创建的订单信息
  console.log("[支付] 准备创建订单:", {
    amount,
    payType,
    productName,
    appHost,
  });

  try {
    // 步骤9：验证app_host是否有效
    // 调用后端API验证当前域名是否允许创建订单
    const verifyResponse = await fetch("/api/payment/verify_host", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ app_host: appHost }),
    });

    // 解析验证结果
    const verifyResult = await verifyResponse.json();

    // 步骤10：检查验证结果
    if (!verifyResult.success) {
      // 域名验证失败，显示错误提示
      // 使用showModalAlert显示域名验证失败的错误信息
      showModalAlert(
        verifyResult.message || "当前域名未授权，无法创建订单",
        "验证失败",
      );
      console.error("[支付] app_host验证失败:", verifyResult.message);
      return;
    }

    // 步骤11：创建支付订单
    // 调用后端API，传入金额、支付方式、商品名称等参数
    const createResponse = await fetch("/api/payment/create", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Session-ID": sessionUUID,
      },
      body: JSON.stringify({
        amount: amount,
        payment_type: "jump",
        payment_method: payType,
        product_name: productName,
        app_host: appHost,
        return_url: window.location.href,
        sub_openid: subOpenid,
        sub_appid: subAppid,
        device: Get_YiPAi_device(),
      }),
    });

    // 解析创建结果
    const createResult = await createResponse.json();

    // 步骤12：检查订单创建结果
    if (!createResult.success) {
      // 订单创建失败，显示错误提示
      // 使用showModalAlert显示创建失败的错误信息
      showModalAlert(
        createResult.message || "创建订单时出错，请稍后重试",
        "创建订单失败",
      );
      console.error("[支付] 创建订单失败:", createResult.message);
      return;
    }

    // 步骤13：订单创建成功，提取支付URL和订单号
    const payUrl = createResult.pay_url;
    const orderId = createResult.order_id;

    // 输出日志：记录订单创建成功
    console.log("[支付] 订单创建成功:", { orderId, payUrl });

    // 步骤14：关闭支付弹窗
    closePaymentModal();

    // 步骤15：在新窗口打开支付URL
    // 使用window.open在新标签页打开支付页面，避免离开当前页面
    window.open(payUrl, "_blank");

    // 步骤16：显示支付提示
    // 使用showModalAlert提示用户订单已创建，请在新页面完成支付
    showModalAlert(
      "请在新打开的页面完成支付，支付完成后会自动刷新订单状态",
      "订单已创建",
    );

    // 步骤17：启动订单状态轮询
    // 每3秒查询一次订单状态，最多查询20次（1分钟）
    startOrderPolling(orderId);
  } catch (error) {
    // 捕获网络错误或其他异常
    console.error("[支付] 创建订单时出错:", error);

    // 显示错误提示
    // 使用showModalAlert显示网络错误信息
    showModalAlert("网络错误，请检查网络连接后重试", "错误");
  }
}

// ========================================
// 查询订单状态函数
// ========================================
/**
 * 查询指定订单的支付状态
 *
 * 功能说明：
 * 1. 调用后端API查询订单状态
 * 2. 返回订单详细信息（状态、金额、时间等）
 *
 * 订单状态说明：
 * - pending: 待支付（用户还未完成支付）
 * - paid: 已支付（支付成功）
 * - closed: 已关闭（订单已取消或超时）
 *
 * @param {string} orderId - 订单号
 * @returns {Promise<Object>} 返回订单信息对象，包含status、order等字段
 */
async function queryOrderStatus(orderId) {
  // 步骤1：参数验证 - 检查订单号是否为空
  if (!orderId) {
    console.error("[支付] 订单号不能为空");
    return { success: false, message: "订单号不能为空" };
  }

  try {
    // 步骤2：调用后端API查询订单状态
    const response = await fetch("/api/payment/query", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Session-ID": sessionUUID,
      },
      body: JSON.stringify({ order_id: orderId }),
    });

    // 步骤3：解析响应数据
    const result = await response.json();

    // 步骤4：输出日志 - 记录查询结果
    console.log("[支付] 查询订单状态:", { orderId, result });

    // 步骤5：返回查询结果
    return result;
  } catch (error) {
    // 捕获网络错误或其他异常
    console.error("[支付] 查询订单状态时出错:", error);

    // 返回错误对象
    return { success: false, message: "查询订单状态失败" };
  }
}

// ========================================
// 启动订单状态轮询函数
// ========================================
/**
 * 启动定时轮询，每3秒查询一次订单状态
 *
 * 功能说明：
 * 1. 使用setInterval创建定时器，每3秒执行一次
 * 2. 每次查询订单状态，如果已支付则停止轮询
 * 3. 最多轮询20次（1分钟），超时后自动停止
 *
 * 使用场景：
 * - 用户创建订单后自动启动轮询
 * - 用户在订单列表点击"查询状态"时启动轮询
 *
 * 注意事项：
 * - 同一时间只能有一个订单在轮询
 * - 轮询前会先清除之前的定时器，避免内存泄漏
 *
 * @param {string} orderId - 订单号
 * @returns {void} 无返回值
 */
function startOrderPolling(orderId) {
  // 步骤1：清除之前的定时器（如果存在）
  // 避免多个订单同时轮询，导致资源浪费
  if (paymentPollingTimer) {
    clearInterval(paymentPollingTimer);
    paymentPollingTimer = null;
  }

  // 步骤2：重置轮询计数器
  paymentPollingCount = 0;

  // 输出日志：记录开始轮询
  console.log("[支付] 开始轮询订单状态:", orderId);

  // 步骤3：创建定时器，每3秒执行一次
  paymentPollingTimer = setInterval(async () => {
    // 步骤4：增加轮询计数
    paymentPollingCount++;

    // 输出日志：记录轮询次数
    console.log(`[支付] 第${paymentPollingCount}次查询订单状态:`, orderId);

    // 步骤5：查询订单状态
    const result = await queryOrderStatus(orderId);

    // 步骤6：检查查询结果
    if (result.success) {
      // 查询成功，获取订单状态
      const status = result.status;

      // 步骤7：判断订单状态
      if (status === "paid") {
        // 订单已支付，停止轮询
        clearInterval(paymentPollingTimer);
        paymentPollingTimer = null;

        // 显示支付成功提示
        Swal.fire({
          icon: "success",
          title: "支付成功",
          text: "订单已支付，感谢您的支持！",
          confirmButtonText: "确定",
        });

        // 输出日志
        console.log("[支付] 订单支付成功:", orderId);

        // 刷新订单列表（如果订单列表弹窗是打开的）
        const ordersModal = document.getElementById("orders-modal");
        if (ordersModal && ordersModal.style.display !== "none") {
          loadPaymentOrders(currentOrderStatus, currentOrdersPage);
        }
      } else if (status === "closed") {
        // 订单已关闭，停止轮询
        clearInterval(paymentPollingTimer);
        paymentPollingTimer = null;

        // 显示订单关闭提示
        Swal.fire({
          icon: "info",
          title: "订单已关闭",
          text: "订单已被关闭或取消",
          confirmButtonText: "确定",
        });

        console.log("[支付] 订单已关闭:", orderId);
      }
    }

    // 步骤8：检查是否达到最大轮询次数
    if (paymentPollingCount >= 20) {
      // 达到最大次数（20次 * 3秒 = 1分钟），停止轮询
      clearInterval(paymentPollingTimer);
      paymentPollingTimer = null;

      // 显示超时提示
      Swal.fire({
        icon: "warning",
        title: "查询超时",
        text: '订单状态查询超时，请稍后在"我的订单"中手动查询',
        confirmButtonText: "确定",
      });

      console.log("[支付] 订单状态查询超时:", orderId);
    }
  }, 3000); // 每3秒执行一次
}

// ========================================
// 打开订单列表弹窗函数
// ========================================
/**
 * 打开订单列表弹窗，显示用户的所有订单
 *
 * 功能说明：
 * 1. 显示订单列表弹窗（orders-modal）
 * 2. 重置筛选条件和分页
 * 3. 加载第一页的订单数据
 *
 * 调用时机：
 * - 用户点击个人中心的"我的订单"按钮时
 * - 用户在支付成功后查看订单时
 *
 * @returns {void} 无返回值
 */
function openOrdersModal() {
  // 步骤1：获取订单列表弹窗DOM元素
  const modal = document.getElementById("orders-modal");

  // 步骤2：检查弹窗元素是否存在
  if (!modal) {
    console.error("[支付] 订单列表弹窗元素不存在");
    return;
  }

  // 步骤3：显示订单列表弹窗
  modal.classList.remove("hidden");
  modal.style.display = "flex";

  // 步骤4：重置筛选条件和分页
  currentOrderStatus = "all"; // 重置为显示全部订单
  currentOrdersPage = 1; // 重置为第1页

  // 步骤5：更新筛选按钮的激活状态
  // 获取所有筛选按钮，移除'active'类，只给"全部"按钮添加
  document.querySelectorAll(".orders-filter-btn").forEach((btn) => {
    btn.classList.remove("active", "bg-sky-500", "text-white");
    if (btn.dataset.status === "all") {
      btn.classList.add("active", "bg-sky-500", "text-white");
    }
  });

  // 步骤6：加载第一页的订单数据
  loadPaymentOrders("all", 1);

  // 输出日志
  console.log("[支付] 订单列表弹窗已打开");
}

// ========================================
// 关闭订单列表弹窗函数
// ========================================
/**
 * 关闭订单列表弹窗
 *
 * 功能说明：
 * 1. 隐藏订单列表弹窗
 * 2. 停止订单轮询（如果正在轮询）
 *
 * @returns {void} 无返回值
 */
function closeOrdersModal() {
  // 获取订单列表弹窗DOM元素
  const modal = document.getElementById("orders-modal");

  // 检查元素是否存在
  if (!modal) return;

  // 隐藏弹窗
  modal.classList.add("hidden");
  modal.style.display = "none";

  // 停止订单轮询
  if (paymentPollingTimer) {
    clearInterval(paymentPollingTimer);
    paymentPollingTimer = null;
  }

  // 输出日志
  console.log("[支付] 订单列表弹窗已关闭");
}

// ========================================
// 加载订单列表函数
// ========================================
/**
 * 从后端加载订单列表并渲染到页面
 *
 * 功能说明：
 * 1. 调用后端API获取订单列表
 * 2. 根据筛选条件和分页参数加载数据
 * 3. 渲染订单卡片到页面
 * 4. 更新分页控件状态
 *
 * 参数说明：
 * @param {string} status - 订单状态筛选，可选值：'all'、'pending'、'paid'、'closed'
 * @param {number} page - 页码，从1开始
 *
 * @returns {Promise<void>} 无返回值的Promise
 */
async function loadPaymentOrders(status, page) {
  // 步骤1：更新全局变量
  currentOrderStatus = status;
  currentOrdersPage = page;

  // 步骤2：获取订单列表容器DOM元素
  const container = document.getElementById("orders-list-container");

  // 步骤3：检查容器是否存在
  if (!container) {
    console.error("[支付] 订单列表容器不存在");
    return;
  }

  // 步骤4：显示加载提示
  container.innerHTML =
    '<p class="text-slate-400 text-center py-10 text-sm">加载中...</p>';

  // 输出日志：记录加载参数
  console.log("[支付] 加载订单列表:", { status, page });

  try {
    // 步骤5：构建API请求URL
    // 拼接查询参数：status、page、per_page
    let url = `/api/payment/orders?page=${page}&per_page=${ordersPerPage}`;

    // 如果status不是'all'，添加status参数进行筛选
    if (status !== "all") {
      url += `&status=${status}`;
    }

    // 步骤6：调用后端API获取订单列表
    const response = await fetch(url, {
      method: "GET",
      headers: {
        "Content-Type": "application/json",
        "X-Session-ID": sessionUUID,
      },
    });

    // 步骤7：解析响应数据
    const result = await response.json();

    // 步骤8：检查API调用结果
    if (!result.success) {
      // 加载失败，显示错误提示
      container.innerHTML = `<p class="text-red-500 text-center py-10 text-sm">${
        result.message || "加载订单失败"
      }</p>`;
      console.error("[支付] 加载订单失败:", result.message);
      return;
    }

    // 步骤9：获取订单列表数据
    const orders = result.orders || [];
    const total = result.total || 0;
    const totalPages = Math.ceil(total / ordersPerPage);

    // 输出日志：记录加载结果
    console.log("[支付] 订单列表加载成功:", { total, orders: orders.length });

    // 步骤10：检查是否有订单数据
    if (orders.length === 0) {
      // 没有订单，显示空状态提示
      container.innerHTML = `
                <div class="text-center py-10">
                    <svg xmlns="http://www.w3.org/2000/svg" class="w-16 h-16 mx-auto text-slate-300 mb-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"></path>
                    </svg>
                    <p class="text-slate-400 text-sm">暂无订单</p>
                </div>
            `;
    } else {
      // 步骤11：渲染订单列表
      // 清空容器，准备插入订单卡片
      container.innerHTML = "";

      // 遍历订单数组，为每个订单创建一个卡片
      orders.forEach((order) => {
        // 创建订单卡片HTML
        const orderCard = createOrderCard(order);

        // 插入到容器中
        container.insertAdjacentHTML("beforeend", orderCard);
      });
    }

    // 步骤12：更新分页控件
    updateOrdersPagination(page, totalPages);
  } catch (error) {
    // 捕获网络错误或其他异常
    console.error("[支付] 加载订单列表时出错:", error);

    // 显示错误提示
    container.innerHTML =
      '<p class="text-red-500 text-center py-10 text-sm">网络错误，请稍后重试</p>';
  }
}

// ========================================
// 创建订单卡片HTML函数
// ========================================
/**
 * 根据订单数据生成订单卡片的HTML字符串
 *
 * 功能说明：
 * 1. 根据订单状态选择不同的样式颜色
 * 2. 格式化订单信息（金额、时间等）
 * 3. 根据订单状态显示不同的操作按钮
 *
 * @param {Object} order - 订单对象，包含order_id、amount、status等字段
 * @returns {string} 返回订单卡片的HTML字符串
 */
function createOrderCard(order) {
  // 步骤1：根据订单状态选择样式颜色和显示文本
  let statusConfig = {};

  switch (order.status) {
    case "pending":
      statusConfig = {
        text: "待支付",
        color: "amber",
        bgColor: "bg-amber-50",
        borderColor: "border-amber-200",
        textColor: "text-amber-700",
      };
      break;
    case "paid":
      statusConfig = {
        text: "已支付",
        color: "green",
        bgColor: "bg-green-50",
        borderColor: "border-green-200",
        textColor: "text-green-700",
      };
      break;
    case "closed":
      statusConfig = {
        text: "已关闭",
        color: "slate",
        bgColor: "bg-slate-50",
        borderColor: "border-slate-200",
        textColor: "text-slate-700",
      };
      break;
    default:
      statusConfig = {
        text: "未知",
        color: "slate",
        bgColor: "bg-slate-50",
        borderColor: "border-slate-200",
        textColor: "text-slate-700",
      };
  }

  // 步骤2：格式化支付方式显示文本
  let payTypeText = "";
  switch (order.pay_type) {
    case "alipay":
      payTypeText = "支付宝";
      break;
    case "wxpay":
      payTypeText = "微信支付";
      break;
    case "bank":
      payTypeText = "网银支付";
      break;
    default:
      payTypeText = order.pay_type || "未知";
  }

  // 步骤3：格式化创建时间
  // 将ISO格式的时间转换为易读格式（如：2024-12-10 10:30:45）
  const createTime = new Date(order.create_time).toLocaleString("zh-CN", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  });

  // 步骤4：生成操作按钮HTML
  let actionButtons = "";

  if (order.status === "pending") {
    // 待支付订单：显示"继续支付"和"查询状态"按钮
    actionButtons = `
            <button onclick="continuePay('${order.order_id}')" 
                class="flex-1 py-2 px-3 bg-sky-500 text-white rounded-lg text-xs font-medium hover:bg-sky-600 transition">
                继续支付
            </button>
            <button onclick="refreshOrderStatus('${order.order_id}')" 
                class="flex-1 py-2 px-3 bg-slate-100 text-slate-700 rounded-lg text-xs font-medium hover:bg-slate-200 transition">
                查询状态
            </button>
        `;
  } else {
    // 已支付或已关闭订单：只显示"查询状态"按钮
    actionButtons = `
            <button onclick="refreshOrderStatus('${order.order_id}')" 
                class="w-full py-2 px-3 bg-slate-100 text-slate-700 rounded-lg text-xs font-medium hover:bg-slate-200 transition">
                查询状态
            </button>
        `;
  }

  // 步骤5：拼接完整的订单卡片HTML
  // 使用模板字符串，支持变量插值和换行
  return `
        <div class="border-2 ${statusConfig.borderColor} ${
          statusConfig.bgColor
        } rounded-xl p-4 space-y-3">
            <!-- 订单头部：订单号和状态 -->
            <div class="flex justify-between items-start">
                <!-- 订单号：使用等宽字体显示，便于复制 -->
                <div>
                    <p class="text-xs text-slate-500">订单号</p>
                    <p class="text-sm font-mono font-semibold text-slate-800">${
                      order.order_id
                    }</p>
                </div>
                <!-- 订单状态徽章 -->
                <span class="px-3 py-1 ${statusConfig.bgColor} ${
                  statusConfig.textColor
                } rounded-full text-xs font-semibold border ${statusConfig.borderColor}">
                    ${statusConfig.text}
                </span>
            </div>
            
            <!-- 订单详情：金额、支付方式、商品名称 -->
            <div class="space-y-2 text-sm">
                <!-- 支付金额：突出显示，使用大号字体 -->
                <div class="flex justify-between">
                    <span class="text-slate-600">支付金额</span>
                    <span class="font-bold text-lg text-sky-600">¥${parseFloat(
                      order.amount,
                    ).toFixed(2)}</span>
                </div>
                <!-- 支付方式 -->
                <div class="flex justify-between">
                    <span class="text-slate-600">支付方式</span>
                    <span class="text-slate-800">${payTypeText}</span>
                </div>
                <!-- 商品名称 -->
                <div class="flex justify-between">
                    <span class="text-slate-600">商品名称</span>
                    <span class="text-slate-800">${
                      order.product_name || "在线支付"
                    }</span>
                </div>
                <!-- 创建时间 -->
                <div class="flex justify-between">
                    <span class="text-slate-600">创建时间</span>
                    <span class="text-slate-500 text-xs">${createTime}</span>
                </div>
            </div>
            
            <!-- 操作按钮区域 -->
            <div class="flex gap-2 pt-2 border-t border-slate-200">
                ${actionButtons}
            </div>
        </div>
    `;
}

// ========================================
// 更新订单列表分页控件函数
// ========================================
/**
 * 更新订单列表的分页控件状态
 *
 * 功能说明：
 * 1. 更新页码显示
 * 2. 更新"上一页"/"下一页"按钮的禁用状态
 *
 * @param {number} currentPage - 当前页码
 * @param {number} totalPages - 总页数
 * @returns {void} 无返回值
 */
function updateOrdersPagination(currentPage, totalPages) {
  // 步骤1：获取分页控件DOM元素
  const pageInfo = document.getElementById("orders-page-info");
  const prevBtn = document.getElementById("orders-prev-btn");
  const nextBtn = document.getElementById("orders-next-btn");

  // 步骤2：更新页码显示
  if (pageInfo) {
    pageInfo.textContent = `第 ${currentPage} / ${totalPages} 页`;
  }

  // 步骤3：更新"上一页"按钮状态
  if (prevBtn) {
    // 如果当前是第1页，禁用"上一页"按钮
    if (currentPage <= 1) {
      prevBtn.disabled = true;
      prevBtn.classList.add("opacity-50", "cursor-not-allowed");
    } else {
      prevBtn.disabled = false;
      prevBtn.classList.remove("opacity-50", "cursor-not-allowed");
    }
  }

  // 步骤4：更新"下一页"按钮状态
  if (nextBtn) {
    // 如果当前是最后一页，禁用"下一页"按钮
    if (currentPage >= totalPages) {
      nextBtn.disabled = true;
      nextBtn.classList.add("opacity-50", "cursor-not-allowed");
    } else {
      nextBtn.disabled = false;
      nextBtn.classList.remove("opacity-50", "cursor-not-allowed");
    }
  }
}

// ========================================
// 继续支付函数
// ========================================
/**
 * 继续支付未完成的订单
 *
 * 功能说明：
 * 1. 查询订单详情获取支付URL
 * 2. 在新窗口打开支付页面
 * 3. 启动订单状态轮询
 *
 * @param {string} orderId - 订单号
 * @returns {Promise<void>} 无返回值的Promise
 */
async function continuePay(orderId) {
  try {
    // 步骤1：查询订单详情
    const result = await queryOrderStatus(orderId);

    // 步骤2：检查查询结果
    if (!result.success) {
      Swal.fire({
        icon: "error",
        title: "错误",
        text: result.message || "查询订单失败",
        confirmButtonText: "确定",
      });
      return;
    }

    // 步骤3：检查订单状态
    if (result.status !== "pending") {
      Swal.fire({
        icon: "info",
        title: "提示",
        text: "该订单不是待支付状态",
        confirmButtonText: "确定",
      });
      return;
    }

    // 步骤4：获取支付URL
    const payUrl = result.order.pay_url;

    // 步骤5：在新窗口打开支付页面
    window.open(payUrl, "_blank");

    // 步骤6：启动订单状态轮询
    startOrderPolling(orderId);

    // 步骤7：显示提示
    Swal.fire({
      icon: "info",
      title: "提示",
      text: "请在新打开的页面完成支付",
      confirmButtonText: "确定",
      timer: 2000,
    });
  } catch (error) {
    console.error("[支付] 继续支付时出错:", error);
    Swal.fire({
      icon: "error",
      title: "错误",
      text: "操作失败，请稍后重试",
      confirmButtonText: "确定",
    });
  }
}

// ========================================
// 刷新订单状态函数
// ========================================
/**
 * 手动刷新订单状态
 *
 * 功能说明：
 * 1. 查询最新的订单状态
 * 2. 更新订单列表显示
 * 3. 显示查询结果提示
 *
 * @param {string} orderId - 订单号
 * @returns {Promise<void>} 无返回值的Promise
 */
async function refreshOrderStatus(orderId) {
  try {
    // 显示加载提示
    Swal.fire({
      title: "查询中...",
      text: "正在查询订单状态",
      allowOutsideClick: false,
      didOpen: () => {
        Swal.showLoading();
      },
    });

    // 步骤1：查询订单状态
    const result = await queryOrderStatus(orderId);

    // 步骤2：关闭加载提示
    Swal.close();

    // 步骤3：检查查询结果
    if (!result.success) {
      Swal.fire({
        icon: "error",
        title: "查询失败",
        text: result.message || "查询订单状态失败",
        confirmButtonText: "确定",
      });
      return;
    }

    // 步骤4：显示查询结果
    let statusText = "";
    let icon = "info";

    switch (result.status) {
      case "paid":
        statusText = "订单已支付";
        icon = "success";
        break;
      case "pending":
        statusText = "订单待支付";
        icon = "info";
        break;
      case "closed":
        statusText = "订单已关闭";
        icon = "warning";
        break;
      default:
        statusText = "订单状态未知";
        icon = "question";
    }

    Swal.fire({
      icon: icon,
      title: statusText,
      text: `订单号：${orderId}`,
      confirmButtonText: "确定",
    });

    // 步骤5：重新加载订单列表
    loadPaymentOrders(currentOrderStatus, currentOrdersPage);
  } catch (error) {
    Swal.close();
    console.error("[支付] 刷新订单状态时出错:", error);
    Swal.fire({
      icon: "error",
      title: "错误",
      text: "查询失败，请稍后重试",
      confirmButtonText: "确定",
    });
  }
}

// ========================================
// 事件监听器绑定区域
// ========================================
// 在DOM加载完成后绑定所有事件监听器
document.addEventListener("DOMContentLoaded", function () {
  // ========== 支付弹窗相关事件 ==========

  // 绑定支付弹窗关闭按钮点击事件
  const paymentCloseBtn = document.getElementById("payment-close-btn");
  if (paymentCloseBtn) {
    paymentCloseBtn.addEventListener("click", closePaymentModal);
  }

  // 绑定支付弹窗取消按钮点击事件
  const paymentCancelBtn = document.getElementById("payment-cancel-btn");
  if (paymentCancelBtn) {
    paymentCancelBtn.addEventListener("click", closePaymentModal);
  }

  // 绑定支付弹窗提交按钮点击事件
  const paymentSubmitBtn = document.getElementById("payment-submit-btn");
  if (paymentSubmitBtn) {
    paymentSubmitBtn.addEventListener("click", createPaymentOrder);
  }

  // 绑定支付弹窗背景点击事件（点击弹窗外部关闭）
  const paymentModal = document.getElementById("payment-modal");
  if (paymentModal) {
    paymentModal.addEventListener("click", function (e) {
      // 只有点击背景（modal本身）时才关闭，点击内容区域不关闭
      if (e.target === paymentModal) {
        closePaymentModal();
      }
    });
  }

  // ========== 订单列表弹窗相关事件 ==========

  // 绑定订单列表弹窗关闭按钮点击事件
  const ordersCloseBtn = document.getElementById("orders-close-btn");
  if (ordersCloseBtn) {
    ordersCloseBtn.addEventListener("click", closeOrdersModal);
  }

  // 绑定订单列表弹窗刷新按钮点击事件
  const ordersRefreshBtn = document.getElementById("orders-refresh-btn");
  if (ordersRefreshBtn) {
    ordersRefreshBtn.addEventListener("click", function () {
      // 重新加载当前页的订单列表
      loadPaymentOrders(currentOrderStatus, currentOrdersPage);
    });
  }

  // 绑定订单列表弹窗背景点击事件
  const ordersModal = document.getElementById("orders-modal");
  if (ordersModal) {
    ordersModal.addEventListener("click", function (e) {
      if (e.target === ordersModal) {
        closeOrdersModal();
      }
    });
  }

  // ========== 订单状态筛选按钮事件 ==========

  // 获取所有筛选按钮并绑定点击事件
  document.querySelectorAll(".orders-filter-btn").forEach((btn) => {
    btn.addEventListener("click", function () {
      // 获取点击按钮的状态值
      const status = this.dataset.status;

      // 更新所有按钮的激活状态
      document.querySelectorAll(".orders-filter-btn").forEach((b) => {
        b.classList.remove("active", "bg-sky-500", "text-white");
      });

      // 给当前按钮添加激活样式
      this.classList.add("active", "bg-sky-500", "text-white");

      // 重新加载订单列表（第1页）
      loadPaymentOrders(status, 1);
    });
  });

  // ========== 订单列表分页按钮事件 ==========

  // 绑定"上一页"按钮点击事件
  const ordersPrevBtn = document.getElementById("orders-prev-btn");
  if (ordersPrevBtn) {
    ordersPrevBtn.addEventListener("click", function () {
      // 检查是否已经是第1页
      if (currentOrdersPage > 1) {
        // 加载上一页
        loadPaymentOrders(currentOrderStatus, currentOrdersPage - 1);
      }
    });
  }

  // 绑定"下一页"按钮点击事件
  const ordersNextBtn = document.getElementById("orders-next-btn");
  if (ordersNextBtn) {
    ordersNextBtn.addEventListener("click", function () {
      // 加载下一页
      loadPaymentOrders(currentOrderStatus, currentOrdersPage + 1);
    });
  }

  // 输出日志：记录事件绑定完成
  console.log("[支付] 支付系统事件监听器已绑定");
});

// ============================================================================
// 彩虹易支付系统 - 管理员功能实现
// ============================================================================
// 本模块实现管理员专用的支付管理功能
// 包括：支付配置管理、支付日志查看等
// ============================================================================

// ========================================
// 支付日志分页全局变量
// ========================================

// 支付日志当前页码
let currentPaymentLogsPage = 1;

// 支付日志每页显示数量
let paymentLogsPerPage = 20;

// ========================================
// 加载支付配置函数（管理员）
// ========================================
/**
 * 从后端加载当前的支付配置并显示到管理面板
 *
 * 功能说明：
 * 1. 调用后端API获取当前启用的支付方式
 * 2. 更新复选框的选中状态
 * 3. 隐藏加载提示，显示配置内容
 *
 * 调用时机：
 * - 管理员首次打开支付配置面板时
 * - 管理员点击"刷新"按钮时
 *
 * @returns {Promise<void>} 无返回值的Promise
 */
async function loadPaymentConfig() {
  // 输出日志：记录开始加载配置
  console.log("[管理员-支付配置] 开始加载支付配置");

  try {
    // 步骤1：调用后端API获取支付配置
    const response = await fetch("/api/admin/payment/config", {
      method: "GET",
      headers: {
        "Content-Type": "application/json",
        "X-Session-ID": sessionUUID,
      },
    });

    // 步骤2：解析响应数据
    const result = await response.json();

    // 步骤3：检查API调用结果
    if (!result.success) {
      // 加载失败，显示错误提示
      Swal.fire({
        icon: "error",
        title: "加载失败",
        text: result.message || "无法加载支付配置",
        confirmButtonText: "确定",
      });
      console.error("[管理员-支付配置] 加载失败:", result.message);
      return;
    }

    // 步骤4：获取启用的支付方式列表
    // 例如：["alipay", "wxpay"]
    const enabledMethods = result.enabled_payment_methods || [];

    // 输出日志：记录当前启用的支付方式
    console.log("[管理员-支付配置] 当前启用的支付方式:", enabledMethods);

    // 步骤5：动态生成支付方式配置复选框
    // 获取配置内容容器
    const configContent = document.getElementById(
      "mobile-multi-admin-payment-config-content",
    );

    // 检查容器是否存在
    if (!configContent) {
      console.error("[管理员-支付配置] 配置容器元素不存在");
      return;
    }

    // 5.1 生成支付方式复选框HTML
    // 创建一个HTML字符串，包含所有支付方式的复选框
    let checkboxesHTML = `
            <!-- 提示信息卡片 -->
            <div class="bg-sky-50 border border-sky-200 rounded-lg p-3">
                <p class="text-xs text-sky-700">
                    <strong>提示：</strong>请至少启用一种支付方式。修改后立即生效，无需重启服务。
                </p>
            </div>

            <!-- 支付方式选择区域 -->
            <div class="space-y-3">
                <!-- 支付方式标题 -->
                <h5 class="text-sm font-semibold text-slate-700">启用的支付方式</h5>
        `;

    // 5.2 遍历全局配置对象(PAYMENT_METHODS)，为每个支付方式创建复选框
    // 使用Object.entries()获取所有的键值对
    Object.entries(PAYMENT_METHODS).forEach(([methodCode, methodConfig]) => {
      // methodCode: 支付方式代码，如 'alipay'
      // methodConfig: 支付方式配置对象，包含 name、icon、svg、borderColor、textColor、description

      // 检查当前支付方式是否在启用列表中
      const isChecked = enabledMethods.includes(methodCode);

      // 根据图标类型生成图标HTML
      // 如果icon字段为'svg'，使用svg字段的SVG代码
      // 否则使用icon字段作为emoji图标
      const iconHtml =
        methodConfig.icon === "svg"
          ? methodConfig.svg // 直接使用SVG代码（已包含样式类）
          : `<span class="text-xl">${methodConfig.icon}</span>`; // emoji图标，包裹在span中

      // 生成复选框HTML
      // 每个复选框包含：图标（SVG或emoji）、名称、描述
      checkboxesHTML += `
                <label class="flex items-center p-3 bg-white border-2 border-slate-200 rounded-lg cursor-pointer ${
                  methodConfig.borderColor
                } transition-colors">
                    <!-- 复选框输入元素 -->
                    <input type="checkbox" 
                           id="payment-method-${methodCode}" 
                           value="${methodCode}" 
                           class="w-4 h-4 ${methodConfig.textColor} rounded" 
                           ${isChecked ? "checked" : ""} />
                    
                    <!-- 支付方式图标：SVG或emoji，根据配置动态生成 -->
                    <span class="ml-3 flex items-center">
                        ${iconHtml}
                    </span>
                    
                    <!-- 支付方式信息：名称和描述 -->
                    <div class="ml-2 flex-1">
                        <span class="text-sm font-medium text-slate-800">${
                          methodConfig.name
                        }</span>
                        <p class="text-xs text-slate-500 mt-0.5">${
                          methodConfig.description
                        }</p>
                    </div>
                </label>
            `;
    });

    // 5.3 添加保存按钮和加载提示
    checkboxesHTML += `
            </div>

            <!-- 保存按钮 -->
            <button id="save-payment-config-btn" 
                class="w-full py-2.5 bg-sky-500 text-white rounded-lg text-sm font-medium hover:bg-sky-600 active:bg-sky-700 transition">
                保存配置
            </button>

            <!-- 加载提示（初始显示） -->
            <div id="payment-config-loading" class="hidden text-center py-4">
                <p class="text-sm text-slate-500">加载中...</p>
            </div>
        `;

    // 5.4 将生成的HTML插入到配置容器中
    configContent.innerHTML = checkboxesHTML;

    // 5.5 重新绑定保存按钮的点击事件
    // 因为innerHTML会替换所有内容，之前绑定的事件会失效
    const saveBtn = document.getElementById("save-payment-config-btn");
    if (saveBtn) {
      saveBtn.addEventListener("click", function () {
        // 调用保存配置函数
        savePaymentConfig();
      });
    }

    // 步骤6：隐藏加载提示（如果存在的话）
    const loadingElement = document.getElementById("payment-config-loading");
    if (loadingElement) {
      loadingElement.style.display = "none";
    }
  } catch (error) {
    // 捕获网络错误或其他异常
    console.error("[管理员-支付配置] 加载时出错:", error);

    // 显示错误提示
    Swal.fire({
      icon: "error",
      title: "错误",
      text: "网络错误，请稍后重试",
      confirmButtonText: "确定",
    });
  }
}

// ========================================
// 保存支付配置函数（管理员）
// ========================================
/**
 * 将管理员修改的支付配置保存到后端
 *
 * 功能说明：
 * 1. 收集复选框的选中状态
 * 2. 验证至少启用了一种支付方式
 * 3. 调用后端API更新配置
 * 4. 显示保存结果提示
 *
 * 调用时机：
 * - 管理员点击"保存配置"按钮时
 *
 * @returns {Promise<void>} 无返回值的Promise
 */
async function savePaymentConfig() {
  // 输出日志：记录开始保存配置
  console.log("[管理员-支付配置] 开始保存支付配置");

  try {
    // 步骤1：动态收集所有支付方式复选框的选中状态
    const enabledMethods = [];

    // 遍历全局配置对象(PAYMENT_METHODS)，检查每个支付方式的复选框
    // 使用Object.keys()获取所有支付方式代码
    Object.keys(PAYMENT_METHODS).forEach((methodCode) => {
      // 根据支付方式代码获取对应的复选框元素
      // 元素ID格式: payment-method-{code}，例如 payment-method-alipay
      const checkbox = document.getElementById(`payment-method-${methodCode}`);

      // 检查复选框是否存在且已勾选
      if (checkbox && checkbox.checked) {
        // 将选中的支付方式代码添加到数组中
        enabledMethods.push(methodCode);
      }
    });

    // 步骤2：验证至少选择了一种支付方式
    if (enabledMethods.length === 0) {
      // 没有选择任何支付方式，显示警告
      Swal.fire({
        icon: "warning",
        title: "提示",
        text: "请至少启用一种支付方式",
        confirmButtonText: "确定",
      });
      return;
    }

    // 步骤3：将数组转换为逗号分隔的字符串
    // 例如：["alipay", "wxpay"] -> "alipay,wxpay"
    const enabledMethodsStr = enabledMethods.join(",");

    // 输出日志：记录即将保存的配置
    console.log("[管理员-支付配置] 即将保存的配置:", enabledMethodsStr);

    // 步骤4：调用后端API更新配置
    const response = await fetch("/api/admin/payment/config", {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
        "X-Session-ID": sessionUUID,
      },
      body: JSON.stringify({
        enabled_payment_methods: enabledMethodsStr,
      }),
    });

    // 步骤5：解析响应数据
    const result = await response.json();

    // 步骤6：检查保存结果
    if (result.success) {
      // 保存成功，显示成功提示
      Swal.fire({
        icon: "success",
        title: "保存成功",
        text: "支付配置已更新，立即生效",
        confirmButtonText: "确定",
        timer: 2000,
      });

      // 输出日志：记录保存成功
      console.log("[管理员-支付配置] 保存成功");
    } else {
      // 保存失败，显示错误提示
      Swal.fire({
        icon: "error",
        title: "保存失败",
        text: result.message || "无法保存支付配置",
        confirmButtonText: "确定",
      });

      // 输出错误日志
      console.error("[管理员-支付配置] 保存失败:", result.message);
    }
  } catch (error) {
    // 捕获网络错误或其他异常
    console.error("[管理员-支付配置] 保存时出错:", error);

    // 显示错误提示
    Swal.fire({
      icon: "error",
      title: "错误",
      text: "网络错误，请稍后重试",
      confirmButtonText: "确定",
    });
  }
}

// ========================================
// 加载支付日志函数（管理员）
// ========================================
/**
 * 从后端加载支付日志列表并渲染到管理面板
 *
 * 功能说明：
 * 1. 收集筛选条件（用户ID、操作类型、日期范围）
 * 2. 调用后端API获取日志数据
 * 3. 渲染日志列表到页面
 * 4. 更新分页控件状态
 *
 * 参数说明：
 * @param {number} page - 页码，从1开始
 *
 * @returns {Promise<void>} 无返回值的Promise
 */
async function loadPaymentLogs(page) {
  // 步骤1：更新全局页码变量
  currentPaymentLogsPage = page;

  // 步骤2：获取日志列表容器DOM元素
  const container = document.getElementById(
    "mobile-multi-admin-payment-logs-list",
  );

  // 步骤3：检查容器是否存在
  if (!container) {
    console.error("[管理员-支付日志] 日志列表容器不存在");
    return;
  }

  // 步骤4：显示加载提示
  container.innerHTML =
    '<p class="text-slate-400 text-center py-10 text-xs">加载中...</p>';

  // 步骤5：收集筛选条件
  // 获取用户ID输入框的值
  const userId =
    document.getElementById("payment-logs-user-id")?.value.trim() || "";

  // 获取操作类型下拉框的值
  const actionType =
    document.getElementById("payment-logs-action-type")?.value || "";

  // 获取开始日期输入框的值
  const startDate =
    document.getElementById("payment-logs-start-date")?.value || "";

  // 获取结束日期输入框的值
  const endDate = document.getElementById("payment-logs-end-date")?.value || "";

  // 输出日志：记录筛选条件
  console.log("[管理员-支付日志] 筛选条件:", {
    userId,
    actionType,
    startDate,
    endDate,
    page,
  });

  try {
    // 步骤6：构建API请求URL
    // 基础URL包含页码和每页数量
    let url = `/api/admin/payment_logs?page=${page}&per_page=${paymentLogsPerPage}`;

    // 如果有用户ID筛选条件，添加到URL
    if (userId) {
      url += `&user_id=${encodeURIComponent(userId)}`;
    }

    // 如果有操作类型筛选条件，添加到URL
    if (actionType) {
      url += `&action_type=${encodeURIComponent(actionType)}`;
    }

    // 如果有开始日期筛选条件，添加到URL
    if (startDate) {
      url += `&start_date=${encodeURIComponent(startDate)}`;
    }

    // 如果有结束日期筛选条件，添加到URL
    if (endDate) {
      url += `&end_date=${encodeURIComponent(endDate)}`;
    }

    // 步骤7：调用后端API获取日志列表
    // 添加X-Session-ID请求头，用于后端身份验证
    // sessionUUID是全局会话标识符，在用户登录时由服务器生成并存储在客户端
    // 后端通过此header验证请求的合法性，防止未授权访问
    const response = await fetch(url, {
      method: "GET", // 明确指定HTTP方法为GET
      headers: {
        "X-Session-ID": sessionUUID, // 添加会话ID用于身份验证
      },
    });

    // 步骤8：检查HTTP状态码
    // 在尝试解析响应数据之前，首先验证HTTP请求是否成功
    // 这样可以更准确地捕获和处理各种HTTP错误（401未授权、403禁止访问、404未找到、500服务器错误等）
    if (!response.ok) {
      // HTTP错误（401, 403, 404, 500等）
      // 首先尝试读取响应体文本，它可能包含详细的错误信息
      const errorText = await response.text();
      // 初始化错误消息，默认显示HTTP状态码
      let errorMessage = `HTTP错误: ${response.status}`;

      try {
        // 尝试将错误文本解析为JSON对象
        // 如果后端返回的是结构化的错误信息，我们可以提取message字段
        const errorData = JSON.parse(errorText);
        errorMessage = errorData.message || errorMessage;
      } catch (e) {
        // 解析失败，使用状态码文本
        // 这种情况下，后端可能返回的是纯文本或HTML错误页面
      }

      // 根据状态码显示不同的错误提示
      // 这样可以为用户提供更友好、更具体的错误说明
      if (response.status === 401) {
        // 401 Unauthorized: 用户未登录或会话已过期
        errorMessage = "未登录或会话已过期，请重新登录";
      } else if (response.status === 403) {
        // 403 Forbidden: 用户已登录但没有足够的权限访问此资源
        errorMessage = "权限不足，需要审计日志查看权限";
      }

      // 在页面上显示错误消息
      // 使用红色文本和居中对齐，确保用户能够清楚地看到错误提示
      container.innerHTML = `<p class="text-red-500 text-center py-10 text-xs">${errorMessage}</p>`;

      // 在控制台记录详细的错误信息，方便开发人员调试
      console.error("[管理员-支付日志] HTTP错误:", {
        status: response.status,
        message: errorMessage,
      });
      return; // 提前返回，不再继续处理
    }

    // 步骤9：解析响应数据（修改原来的步骤8）
    // 只有在HTTP请求成功（status 200-299）时，才会执行到这里
    const result = await response.json();

    // 步骤10：检查API调用结果（修改原来的步骤9）
    // 即使HTTP请求成功（200 OK），API调用本身也可能失败
    // 例如：后端业务逻辑检测到错误、数据库查询失败等
    if (!result.success) {
      // 加载失败，显示错误提示
      // result.message包含后端返回的具体错误信息
      container.innerHTML = `<p class="text-red-500 text-center py-10 text-xs">${
        result.message || "加载日志失败"
      }</p>`;
      console.error("[管理员-支付日志] 加载失败:", result.message);
      return; // 提前返回，不再继续处理
    }

    // 步骤11：获取日志列表数据（修改原来的步骤10）
    const logs = result.logs || [];
    const total = result.total || 0;
    const totalPages = Math.ceil(total / paymentLogsPerPage);

    // 输出日志：记录加载结果
    console.log("[管理员-支付日志] 日志列表加载成功:", {
      total,
      logs: logs.length,
    });

    // 步骤12：检查是否有日志数据（修改原来的步骤11）
    if (logs.length === 0) {
      // 没有日志，显示空状态提示
      container.innerHTML = `
                <div class="text-center py-10">
                    <svg xmlns="http://www.w3.org/2000/svg" class="w-12 h-12 mx-auto text-slate-300 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path>
                    </svg>
                    <p class="text-slate-400 text-xs">暂无日志记录</p>
                </div>
            `;
    } else {
      // 步骤13：渲染日志列表（修改原来的步骤12）
      // 清空容器，准备插入日志卡片
      container.innerHTML = "";

      // 遍历日志数组，为每条日志创建一个卡片
      logs.forEach((log) => {
        // 创建日志卡片HTML
        const logCard = createPaymentLogCard(log);

        // 插入到容器中
        container.insertAdjacentHTML("beforeend", logCard);
      });
    }

    // 步骤13：更新分页控件
    updatePaymentLogsPagination(page, totalPages);
  } catch (error) {
    // 捕获网络错误或其他异常
    console.error("[管理员-支付日志] 加载时出错:", error);

    // 显示错误提示
    container.innerHTML =
      '<p class="text-red-500 text-center py-10 text-xs">网络错误，请稍后重试</p>';
  }
}

// ========================================
// 创建支付日志卡片HTML函数
// ========================================
/**
 * 根据日志数据生成日志卡片的HTML字符串
 *
 * 功能说明：
 * 1. 根据操作类型选择不同的样式颜色
 * 2. 格式化日志信息（时间、数据等）
 * 3. 将JSON数据格式化显示
 *
 * @param {Object} log - 日志对象，包含user_id、action、log_data等字段
 * @returns {string} 返回日志卡片的HTML字符串
 */
function createPaymentLogCard(log) {
  // 步骤1：根据操作类型选择样式颜色
  let actionConfig = {};

  switch (log.action) {
    case "create_order":
      actionConfig = {
        text: "创建订单",
        color: "blue",
        bgColor: "bg-blue-50",
        borderColor: "border-blue-200",
        textColor: "text-blue-700",
      };
      break;
    case "query_order":
      actionConfig = {
        text: "查询订单",
        color: "purple",
        bgColor: "bg-purple-50",
        borderColor: "border-purple-200",
        textColor: "text-purple-700",
      };
      break;
    case "payment_success":
      actionConfig = {
        text: "支付成功",
        color: "green",
        bgColor: "bg-green-50",
        borderColor: "border-green-200",
        textColor: "text-green-700",
      };
      break;
    case "payment_fail":
      actionConfig = {
        text: "支付失败",
        color: "red",
        bgColor: "bg-red-50",
        borderColor: "border-red-200",
        textColor: "text-red-700",
      };
      break;
    case "config_update":
      actionConfig = {
        text: "配置更新",
        color: "amber",
        bgColor: "bg-amber-50",
        borderColor: "border-amber-200",
        textColor: "text-amber-700",
      };
      break;
    default:
      actionConfig = {
        text: log.action || "未知操作",
        color: "slate",
        bgColor: "bg-slate-50",
        borderColor: "border-slate-200",
        textColor: "text-slate-700",
      };
  }

  // 步骤2：格式化创建时间
  // 将ISO格式的时间转换为易读格式（如：2024-12-10 10:30:45）
  const createTime = new Date(log.create_time).toLocaleString("zh-CN", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  });

  // 步骤3：格式化日志数据
  // 将JSON对象转换为格式化的字符串，缩进2个空格
  let logDataHTML = "";
  if (log.log_data) {
    try {
      // 尝试解析JSON数据（如果是字符串）
      const logDataObj =
        typeof log.log_data === "string"
          ? JSON.parse(log.log_data)
          : log.log_data;

      // 将对象转换为格式化的JSON字符串
      const logDataStr = JSON.stringify(logDataObj, null, 2);

      // 生成HTML
      logDataHTML = `
                <div class="mt-2">
                    <p class="text-xs font-semibold text-slate-700 mb-1">详细数据</p>
                    <pre class="text-xs text-slate-600 bg-white p-2 rounded border border-slate-200 overflow-x-auto font-mono">${logDataStr}</pre>
                </div>
            `;
    } catch (e) {
      // JSON解析失败，直接显示原始字符串
      logDataHTML = `
                <div class="mt-2">
                    <p class="text-xs font-semibold text-slate-700 mb-1">详细数据</p>
                    <p class="text-xs text-slate-600 bg-white p-2 rounded border border-slate-200">${log.log_data}</p>
                </div>
            `;
    }
  }

  // 步骤4：拼接完整的日志卡片HTML
  return `
        <div class="border-2 ${actionConfig.borderColor} ${
          actionConfig.bgColor
        } rounded-lg p-3 space-y-2">
            <!-- 日志头部：操作类型和时间 -->
            <div class="flex justify-between items-start">
                <!-- 操作类型徽章 -->
                <span class="px-2 py-1 ${actionConfig.bgColor} ${
                  actionConfig.textColor
                } rounded text-xs font-semibold border ${actionConfig.borderColor}">
                    ${actionConfig.text}
                </span>
                <!-- 时间 -->
                <span class="text-xs text-slate-500">${createTime}</span>
            </div>
            
            <!-- 日志详情 -->
            <div class="space-y-1 text-xs">
                <!-- 用户ID -->
                <div class="flex justify-between">
                    <span class="text-slate-600">用户ID</span>
                    <span class="text-slate-800 font-medium">${
                      log.user_id || "系统"
                    }</span>
                </div>
                <!-- 订单ID（如果有） -->
                ${
                  log.order_id
                    ? `
                    <div class="flex justify-between">
                        <span class="text-slate-600">订单ID</span>
                        <span class="text-slate-800 font-mono text-xs">${log.order_id}</span>
                    </div>
                `
                    : ""
                }
            </div>
            
            <!-- 详细数据 -->
            ${logDataHTML}
        </div>
    `;
}

// ========================================
// 更新支付日志分页控件函数
// ========================================
/**
 * 更新支付日志的分页控件状态
 *
 * 功能说明：
 * 1. 更新页码显示
 * 2. 更新"上一页"/"下一页"按钮的禁用状态
 *
 * @param {number} currentPage - 当前页码
 * @param {number} totalPages - 总页数
 * @returns {void} 无返回值
 */
function updatePaymentLogsPagination(currentPage, totalPages) {
  // 步骤1：获取分页控件DOM元素
  const pageInfo = document.getElementById("payment-logs-page-info");
  const prevBtn = document.getElementById("payment-logs-prev-btn");
  const nextBtn = document.getElementById("payment-logs-next-btn");

  // 步骤2：更新页码显示
  if (pageInfo) {
    pageInfo.textContent = `第 ${currentPage} / ${totalPages} 页`;
  }

  // 步骤3：更新"上一页"按钮状态
  if (prevBtn) {
    // 如果当前是第1页，禁用"上一页"按钮
    if (currentPage <= 1) {
      prevBtn.disabled = true;
      prevBtn.classList.add("opacity-50", "cursor-not-allowed");
    } else {
      prevBtn.disabled = false;
      prevBtn.classList.remove("opacity-50", "cursor-not-allowed");
    }
  }

  // 步骤4：更新"下一页"按钮状态
  if (nextBtn) {
    // 如果当前是最后一页，禁用"下一页"按钮
    if (currentPage >= totalPages) {
      nextBtn.disabled = true;
      nextBtn.classList.add("opacity-50", "cursor-not-allowed");
    } else {
      nextBtn.disabled = false;
      nextBtn.classList.remove("opacity-50", "cursor-not-allowed");
    }
  }
}

// ========================================
// 管理员事件监听器绑定区域
// ========================================
// 在DOM加载完成后绑定管理员相关的事件监听器
document.addEventListener("DOMContentLoaded", function () {
  // ========== 支付配置面板相关事件 ==========

  // 绑定刷新支付配置按钮点击事件
  const refreshPaymentConfigBtn = document.getElementById(
    "mobile-multi-admin-refresh-payment-config",
  );
  if (refreshPaymentConfigBtn) {
    refreshPaymentConfigBtn.addEventListener("click", function () {
      // 重新加载支付配置
      loadPaymentConfig();
    });
  }

  // 绑定保存支付配置按钮点击事件
  const savePaymentConfigBtn = document.getElementById(
    "save-payment-config-btn",
  );
  if (savePaymentConfigBtn) {
    savePaymentConfigBtn.addEventListener("click", function () {
      // 保存支付配置
      savePaymentConfig();
    });
  }

  // ========== 支付日志面板相关事件 ==========

  // 绑定刷新支付日志按钮点击事件
  const refreshPaymentLogsBtn = document.getElementById(
    "mobile-multi-admin-refresh-payment-logs",
  );
  if (refreshPaymentLogsBtn) {
    refreshPaymentLogsBtn.addEventListener("click", function () {
      // 重新加载当前页的支付日志
      loadPaymentLogs(currentPaymentLogsPage);
    });
  }

  // 绑定查询支付日志按钮点击事件
  const searchPaymentLogsBtn = document.getElementById(
    "search-payment-logs-btn",
  );
  if (searchPaymentLogsBtn) {
    searchPaymentLogsBtn.addEventListener("click", function () {
      // 使用筛选条件重新加载第1页
      loadPaymentLogs(1);
    });
  }

  // 绑定支付日志"上一页"按钮点击事件
  const paymentLogsPrevBtn = document.getElementById("payment-logs-prev-btn");
  if (paymentLogsPrevBtn) {
    paymentLogsPrevBtn.addEventListener("click", function () {
      // 检查是否已经是第1页
      if (currentPaymentLogsPage > 1) {
        // 加载上一页
        loadPaymentLogs(currentPaymentLogsPage - 1);
      }
    });
  }

  // 绑定支付日志"下一页"按钮点击事件
  const paymentLogsNextBtn = document.getElementById("payment-logs-next-btn");
  if (paymentLogsNextBtn) {
    paymentLogsNextBtn.addEventListener("click", function () {
      // 加载下一页
      loadPaymentLogs(currentPaymentLogsPage + 1);
    });
  }

  // 输出日志：记录管理员事件绑定完成
  console.log("[管理员-支付] 管理员事件监听器已绑定");
});

